import { t as db } from "../../chunks/db.js";
import { t as WalletService } from "../../chunks/wallet.service.js";
//#region src/routes/+layout.server.ts
var load = async ({ locals }) => {
	if (locals.user) {
		const balance = await WalletService.getBalance(locals.user.id);
		const [notifications] = await db.execute(`SELECT id, profile_id as profileId, title, message, \`read\`, created_at as createdAt
       FROM notifications 
       WHERE profile_id = ? AND \`read\` = 0 
       ORDER BY created_at DESC`, [locals.user.id]);
		return {
			user: locals.user,
			balance,
			notifications: notifications.map((n) => ({
				id: n.id,
				profileId: n.profileId,
				title: n.title,
				message: n.message,
				read: Boolean(n.read),
				createdAt: new Date(n.createdAt)
			}))
		};
	}
	return {
		user: null,
		balance: 0,
		notifications: []
	};
};
//#endregion
export { load };
